function fail(msg) { throw new Error(msg); }

const triggerItem = $items('Resume Form Webhook', 0, 0)[0]?.json || {};
const body = triggerItem.body && typeof triggerItem.body === 'object' ? triggerItem.body : triggerItem;

const jd = String(body.jd || '').trim();
const jt = String(body.jt || '').trim();
const company = String(body.company || '').trim();
const selectedResume = String(body.selectedResume || '').trim();

if (!jd) fail('Missing required field: jd');
if (!jt) fail('Missing required field: jt');
if (!company) fail('Missing required field: company');
if (!selectedResume) fail('Missing required field: selectedResume');
if (!selectedResume.endsWith('.tex')) fail('selectedResume must be a .tex file name');

return [{ json: { jd, jt, company, selectedResume } }];

function extractDraft(item) {
  if (typeof item.code === 'string') return item.code;
  if (item.output && typeof item.output.code === 'string') return item.output.code;
  if (typeof item.output === 'string') {
    try {
      const parsed = JSON.parse(item.output);
      if (typeof parsed.code === 'string') return parsed.code;
    } catch {}
  }
  if (typeof item.text === 'string') return item.text;
  return '';
}

const draftLatex = extractDraft($json).trim();
if (!draftLatex) throw new Error('No draft LaTeX generated by GPT.');

const data = $('Parse Optimize Input').item.json;
const companyPath = data.company.replace(/\s+/g, '_').replace(/[^a-zA-Z0-9._-]/g, '_');
const jtPath = data.jt.replace(/\s+/g, '_').replace(/[^a-zA-Z0-9._-]/g, '_');

return [{
  json: {
    success: true,
    message: 'Draft generated. Review and edit before final save.',
    selectedResume: data.selectedResume,
    company: data.company,
    jt: data.jt,
    companyPath,
    jtPath,
    draftLatex
  }
}];

function fail(msg) { throw new Error(msg); }

const triggerItem = $items('Resume Preview Webhook', 0, 0)[0]?.json || {};
const body = triggerItem.body && typeof triggerItem.body === 'object' ? triggerItem.body : triggerItem;

const company = String(body.company || '').trim();
const jt = String(body.jt || '').trim();
const latexContent = String(body.latexContent || '').trim();

if (!company) fail('Missing required field: company');
if (!jt) fail('Missing required field: jt');
if (!latexContent) fail('Missing required field: latexContent');

const companyPath = company.replace(/\s+/g, '_').replace(/[^a-zA-Z0-9._-]/g, '_');
const jtPath = jt.replace(/\s+/g, '_').replace(/[^a-zA-Z0-9._-]/g, '_');
const outputDirectory = `/apps/${companyPath}/${jtPath}`;
const latexB64 = Buffer.from(latexContent, 'utf8').toString('base64');

return [{
  json: {
    company,
    jt,
    companyPath,
    jtPath,
    outputDirectory,
    latexB64
  }
}];

